messages.content:
{
  "children": [
    {
      "name": "RegisterPatient",
      "purpose": "Register a new patient in the system",
      "behavior": "Extract patient details from input, validate uniqueness, and store in patients data store",
      "boundary": {
        "in_scope": [
          "patient registration",
          "input validation",
          "data store write"
        ],
        "out_of_scope": [
          "appointment booking",
          "record retrieval",
          "profile updates"
        ]
      },
      "semantic_inputs": [
        "input: JSON with patient details (name, age, contact, medical_history)"
      ],
      "semantic_outputs": [
        "result: JSON with success, patient_id, message"
      ],
      "preconditions": [
        "input contains valid patient data",
        "patient does not already exist"
      ],
      "postconditions": [
        "patient record created in patients data store"
      ],
      "guarantees": [
        "patient ID is unique",
        "registration is atomic"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "patient_data",
          "type": "dict",
          "description": "Patient details including name, age, contact, medical_history",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "JSON with success status, patient_id, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def RegisterPatient(patient_data: dict) -> dict"
    },
    {
      "name": "BookAppointment",
      "purpose": "Book an appointment for a registered patient",
      "behavior": "Validate patient exists, check appointment slot availability, and store appointment in appointments data store",
      "boundary": {
        "in_scope": [
          "appointment booking",
          "patient existence check",
          "slot validation"
        ],
        "out_of_scope": [
          "patient registration",
          "record retrieval",
          "profile updates"
        ]
      },
      "semantic_inputs": [
        "input: JSON with patient_id, doctor, date, time"
      ],
      "semantic_outputs": [
        "result: JSON with success, appointment_id, message"
      ],
      "preconditions": [
        "patient is registered",
        "appointment slot is available"
      ],
      "postconditions": [
        "appointment record created in appointments data store"
      ],
      "guarantees": [
        "appointment ID is unique",
        "booking is atomic"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "appointment_data",
          "type": "dict",
          "description": "Appointment details including patient_id, doctor, date, time",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "JSON with success status, appointment_id, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def BookAppointment(appointment_data: dict) -> dict"
    },
    {
      "name": "GetRecords",
      "purpose": "Retrieve medical records for a registered patient",
      "behavior": "Validate patient exists, fetch records from patients data store (append-only), and return them",
      "boundary": {
        "in_scope": [
          "record retrieval",
          "patient existence check",
          "data store read"
        ],
        "out_of_scope": [
          "registration",
          "appointment booking",
          "profile updates"
        ]
      },
      "semantic_inputs": [
        "input: JSON with patient_id"
      ],
      "semantic_outputs": [
        "result: JSON with success, records, message"
      ],
      "preconditions": [
        "patient is registered"
      ],
      "postconditions": [
        "records are returned without modification"
      ],
      "guarantees": [
        "records are append-only, no deletion"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "patient_id",
          "type": "str",
          "description": "Unique identifier of the patient",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "JSON with success status, records list, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def GetRecords(patient_id: str) -> dict"
    },
    {
      "name": "UpdateProfile",
      "purpose": "Update profile information for a registered patient",
      "behavior": "Validate patient exists, update patient profile fields in patients data store",
      "boundary": {
        "in_scope": [
          "profile update",
          "patient existence check",
          "data store write"
        ],
        "out_of_scope": [
          "registration",
          "appointment booking",
          "record retrieval"
        ]
      },
      "semantic_inputs": [
        "input: JSON with patient_id and updated fields"
      ],
      "semantic_outputs": [
        "result: JSON with success, updated_profile, message"
      ],
      "preconditions": [
        "patient is registered",
        "input contains valid profile fields"
      ],
      "postconditions": [
        "patient profile updated in patients data store"
      ],
      "guarantees": [
        "update is atomic",
        "only specified fields are changed"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "update_data",
          "type": "dict",
          "description": "JSON with patient_id and fields to update (e.g., contact, address)",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "result",
          "type": "dict",
          "description": "JSON with success status, updated profile, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def UpdateProfile(update_data: dict) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "input": "RegisterPatient, BookAppointment, GetRecords, UpdateProfile"
    },
    "parent_outputs_produced_by": {
      "output": "RegisterPatient, BookAppointment, GetRecords, UpdateProfile"
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "RegisterPatient",
      "to_input": "patient_data",
      "note": "route registration command to RegisterPatient"
    },
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "BookAppointment",
      "to_input": "appointment_data",
      "note": "route booking command to BookAppointment"
    },
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "GetRecords",
      "to_input": "patient_id",
      "note": "route records command to GetRecords"
    },
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "UpdateProfile",
      "to_input": "update_data",
      "note": "route update command to UpdateProfile"
    },
    {
      "from_node": "RegisterPatient",
      "from_output": "result",
      "to_node": "parent",
      "to_input": "output",
      "note": "return registration result to parent"
    },
    {
      "from_node": "BookAppointment",
      "from_output": "result",
      "to_node": "parent",
      "to_input": "output",
      "note": "return booking result to parent"
    },
    {
      "from_node": "GetRecords",
      "from_output": "result",
      "to_node": "parent",
      "to_input": "output",
      "note": "return records to parent"
    },
    {
      "from_node": "UpdateProfile",
      "from_output": "result",
      "to_node": "parent",
      "to_input": "output",
      "note": "return update result to parent"
    }
  ]
}
